-- 007_curated_questions.sql
-- Curated questions library for AskWomensAI

CREATE TABLE IF NOT EXISTS public.curated_questions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  slug text UNIQUE NOT NULL,
  question text NOT NULL,
  category text NOT NULL,
  age_group text,
  is_weird boolean DEFAULT false,
  is_featured boolean DEFAULT false,
  search_request_id uuid REFERENCES search_requests(id),
  meta_title text,
  meta_description text,
  created_at timestamptz DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_curated_questions_category ON public.curated_questions(category);
CREATE INDEX IF NOT EXISTS idx_curated_questions_age_group ON public.curated_questions(age_group);
CREATE INDEX IF NOT EXISTS idx_curated_questions_is_weird ON public.curated_questions(is_weird);
CREATE INDEX IF NOT EXISTS idx_curated_questions_is_featured ON public.curated_questions(is_featured);

ON CONFLICT (slug) DO NOTHING;

-- Total: 549 questions